UPDATE archivio_items SET abstract = 'Due persone sono state arrestate dalla polizia a Torino, i due, avevvano preso in affitto un''alloggio che usavano per spacciare cocaina, a quanto pare i clienti dopo aver comprato la coca, potevano tranquillamente sniffarla nell''alloggio indisturbati.' WHERE id_originale = 7235;
UPDATE archivio_items SET abstract = 'I magistrati di Torino, che stanno indagando sull''omicidio del piccolo Samuele, trovato morto nel suo letto, stanno indagando per calunni, i suoi genitori e due periti incaricati della difesa, perché a quanto pare, hanno fatto il nome di un vicino di casa come probabile assassino del bambino.' WHERE id_originale = 7239;
UPDATE archivio_items SET abstract = 'All''Auditorium di Roma è stata allestita una pista di ghiaccio per pattinare. Molti i giovani che hanno usuffruito di questa opportunità anche i bambini rom che hanno potuto pattinare assieme agli altri ragazzi. Attrazioni al Circo su ghiaccio di Mosca, ospite del festival Russo della capitale. Sul sito www.rai.it i giovani possono navigare su Internet in modo sicuro; attivo durante il periodo natalizzio, si possono trovare tutti i programmi in onda da oggi fino al giorno dell''Epifania, giochi divertenti, alcuni da stampare e ritagliare per giocare con mamma e papà.' WHERE id_originale = 7249;
